         display: flex;\\n          flex-direction: column;\\n          gap: 20px;\\n\\n          .block-img {\\n            width: 60px;\\n            height: 60px;\\n          }\\n\\n          h3 {\\n            font-weight: 500;\\n            color: $primaryColor;\\n          }\\n\\n          .btn-cta {\\n            text-decoration: none;\\n            border-bottom: none;\\n          }\\n        }\\n      }\\n    }\\n\\n    .btn-cta {\\n      &.section {\\n        background-color: $secondaryColor;\\n        color: $white;\\n        padding: 15px 50px;\\n        border-bottom: none;\\n        margin: auto;\\n        transition: all ease-in 200ms;\\n\\n        &::after {\\n          color: $white;\\n        }\\n\\n        &:hover {\\n          background-color: $primaryColor;\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/base.scss\\\" as *;\\n@use \\\"./../variables/colors.scss\\\" as *;\\n@use \\\"./../variables/fonts.scss\\\" as *;\\n@use \\\"./../variables/cta.scss\\\" as *;\\n\\n.section-txt-g-img-d {\\n  border-top: 1px solid $lightGray;\\n  border-bottom: 1px solid $lightGray;\\n  position: relative;\\n  padding: 150px 0;\\n\\n  .container-bg {\\n    background: linear-gradient(\\n      90deg,\\n      $lightGray 0%,\\n      $whiteTransparent calc(0% + 1px),\\n      $whiteTransparent calc(50%),\\n      $lightGray 50%,\\n      $whiteTransparent calc(50% + 1px),\\n      $whiteTransparent calc(100% - 1px),\\n      $lightGray 100%\\n    );\\n    height: 100%;\\n    position: absolute;\\n    z-index: -1;\\n    left: 33.3vw;\\n    width: 33.3vw;\\n    top: 0;\\n  }\\n\\n  .container {\\n    gap: 100px;\\n    align-items: center;\\n\\n    .colg {\\n      display: flex;\\n      flex-direction: column;\\n      gap: 50px;\\n      height: fit-content;\\n    }\\n\\n    .cold {\\n      .block-img {\\n        height: 750px;\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/base.scss\\\" as *;\\n@use \\\"./../variables/colors.scss\\\" as *;\\n@use \\\"./../variables/fonts.scss\\\" as *;\\n@use \\\"./../variables/cta.scss\\\" as *;\\n\\n.section-galerie-vertical {\\n  padding: 50px 0;\\n\\n  .swiper-vertical {\\n    max-height: 80vh;\\n    max-width: 95vw;\\n\\n    .swiper-wrapper {\\n      .swiper-slide {\\n        display: flex;\\n        align-items: center;\\n\\n        .col-50 {\\n          width: 50%;\\n        }\\n\\n        .colg {\\n          height: 100%;\\n          .block-img {\\n            height: 100%;\\n          }\\n        }\\n\\n        .cold {\\n          padding-left: 50px;\\n\\n          .content {\\n            display: flex;\\n            flex-direction: column;\\n            gap: 20px;\\n            width: 70%;\\n\\n            p {\\n              text-align: justify;\\n            }\\n          }\\n        }\\n      }\\n    }\\n\\n    .swiper-pagination-vertical {\\n      .swiper-pagination-bullet {\\n        height: 60px;\\n        width: 2px;\\n        border-radius: 0;\\n        background-color: $lightGray;\\n\\n        &.swiper-pagination-bullet-active {\\n          background-color: $txtColor;\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/base.scss\\\" as *;\\n@use \\\"./../variables/colors.scss\\\" as *;\\n@use \\\"./../variables/fonts.scss\\\" as *;\\n@use \\\"./../variables/cta.scss\\\" as *;\\n\\n.section-step {\\n  padding: 100px 0;\\n  overflow: hidden;\\n\\n  .content-title {\\n    margin-left: 40%;\\n\\n    .surtitre {\\n      display: block;\\n      font-size: 12px;\\n      letter-spacing: 0.25em;\\n      text-transform: uppercase;\\n      color: $secondaryColor;\\n      margin-bottom: 20px;\\n    }\\n\\n    .main-title {\\n      max-width: 540px;\\n    }\\n  }\\n\\n  .slider-layout {\\n    position: relative;\\n    margin-top: -160px;\\n  }\\n\\n  .slide-inner {\\n    display: flex;\\n    justify-content: space-between;\\n    align-items: flex-end;\\n    gap: 150px;\\n    min-height: 500px;\\n\\n    .colg {\\n      width: 35%;\\n\\n      .block-img {\\n        width: 100%;\\n        height: 600px;\\n        overflow: hidden;\\n        transform: translateX(-40px);\\n        opacity: 0;\\n        transition:\\n          transform 0.5s ease,\\n          opacity 0.5s ease;\\n\\n        &.is-visible {\\n          transform: translateX(0);\\n          opacity: 1;\\n        }\\n      }\\n    }\\n\\n    .cold {\\n      width: 33%;\\n      transform: translateX(40px);\\n      opacity: 0;\\n      transition:\\n        transform 0.8s ease 0.15s,\\n        opacity 0.8s ease 0.15s;\\n\\n      &.is-visible {\\n        transform: translateX(0);\\n        opacity: 1;\\n      }\\n\\n      .slide-title {\\n        margin-bottom: 24px;\\n\\n        h3,\\n        h4 {\\n          margin: 0;\\n        }\\n      }\\n\\n      .slide-text {\\n        p:last-child {\\n          margin-bottom: 0;\\n        }\\n      }\\n    }\\n  }\\n\\n  .block-navigation {\\n    position: absolute;\\n    left: 40%;\\n    bottom: 0;\\n    z-index: 5;\\n    display: flex;\\n    flex-direction: column;\\n    gap: 5px;\\n  }\\n\\n  .swiper-step-prev,\\n  .swiper-step-next {\\n    width: 80px;\\n    height: 80px;\\n    display: flex;\\n    align-items: center;\\n    justify-content: center;\\n    border: 1px solid $txtColor;\\n    border-radius: 50%;\\n    cursor: pointer;\\n    position: relative;\\n    transition:\\n      opacity 0.3s ease,\\n      transform 0.3s ease;\\n\\n    &:hover {\\n      transform: scale(1.05);\\n    }\\n\\n    &.swiper-button-disabled {\\n      opacity: 0.4;\\n      pointer-events: none;\\n    }\\n  }\\n\\n  .swiper-step-scrollbar {\\n    position: relative;\\n    margin-top: 100px;\\n    height: 1px !important;\\n    background: $lightGray;\\n  }\\n\\n  .swiper-scrollbar-drag {\\n    height: 2px !important;\\n    top: -0.5px;\\n    background: $txtColor;\\n  }\\n\\n  @media (max-width: 991px) {\\n    .content-title,\\n    .slide-inner {\\n      grid-template-columns: 1fr;\\n      gap: 30px;\\n    }\\n\\n    .block-navigation {\\n      position: static;\\n      transform: none;\\n      flex-direction: row;\\n      margin-top: 30px;\\n      margin-bottom: 20px;\\n    }\\n\\n    .colg .block-img {\\n      max-width: 100%;\\n    }\\n  }\\n}\\n\",\".section-image-parallax {\\n  width: 100vw;\\n  position: relative;\\n\\n  img {\\n    height: 100%;\\n    width: 100%;\\n    object-fit: cover;\\n  }\\n}\\n\",\"@use \\\"./../variables/base.scss\\\" as *;\\n@use \\\"./../variables/colors.scss\\\" as *;\\n@use \\\"./../variables/fonts.scss\\\" as *;\\n@use \\\"./../variables/cta.scss\\\" as *;\\n\\n.section-formulaire-contact {\\n  padding: 100px 0;\\n\\n  .container {\\n    gap: 100px;\\n\\n    .col-35 {\\n      width: 45%;\\n      display: flex;\\n      flex-direction: column;\\n      gap: 50px;\\n\\n      .block-contact {\\n        display: flex;\\n        flex-direction: column;\\n        gap: 20px;\\n        margin-top: 300px;\\n\\n        h3 {\\n          text-transform: uppercase;\\n          letter-spacing: 1px;\\n          font-weight: 600;\\n        }\\n\\n        .block-tel-mail {\\n          .labelBold {\\n            font-weight: 600;\\n            margin-right: 10px;\\n          }\\n        }\\n      }\\n    }\\n\\n    .col-65 {\\n      width: 55%;\\n\\n      form {\\n        display: flex;\\n        flex-direction: column;\\n        gap: 20px;\\n        margin-top: 150px;\\n\\n        .content {\\n          display: flex;\\n          width: 100%;\\n\\n          &.-flex {\\n            p {\\n              display: flex;\\n              gap: 10px;\\n\\n              span {\\n                input,\\n                label {\\n                  width: 100%;\\n                }\\n              }\\n            }\\n          }\\n\\n          p {\\n            width: 100%;\\n\\n            input,\\n            label,\\n            textarea {\\n              border-bottom: 1px solid $lightGray;\\n              display: flex;\\n              justify-content: space-between;\\n              padding: 20px;\\n              width: 100%;\\n              outline: none;\\n\\n              &:focus {\\n                border-color: $secondaryColor;\\n              }\\n            }\\n\\n            select {\\n              outline: none;\\n            }\\n          }\\n        }\\n\\n        input[type=\\\"submit\\\"] {\\n          padding: 10px 50px;\\n          background: $primaryColor;\\n          color: $white;\\n          text-transform: uppercase;\\n          font-weight: 500;\\n          letter-spacing: 3px;\\n          transition: all ease-in 300ms;\\n\\n          &:hover {\\n            background-color: $secondaryColor;\\n            color: $primaryColor;\\n          }\\n        }\\n\\n        .wpcf7-not-valid-tip {\\n          font-size: 0.9rem;\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@charset \\\"UTF-8\\\";\\n/*!\\n * Hamburgers\\n * @description Tasty CSS-animated hamburgers\\n * @author Jonathan Suh @jonsuh\\n * @site https://jonsuh.com/hamburgers\\n * @link https://github.com/jonsuh/hamburgers\\n */\\n\\n// Settings\\n// ==================================================\\n$hamburger-padding-x           : 15px !default;\\n$hamburger-padding-y           : 15px !default;\\n$hamburger-layer-width         : 40px !default;\\n$hamburger-layer-height        : 4px !default;\\n$hamburger-layer-spacing       : 6px !default;\\n$hamburger-layer-color         : #000 !default;\\n$hamburger-layer-border-radius : 4px !default;\\n$hamburger-hover-opacity       : 0.7 !default;\\n$hamburger-active-layer-color  : $hamburger-layer-color !default;\\n$hamburger-active-hover-opacity: $hamburger-hover-opacity !default;\\n\\n// To use CSS filters as the hover effect instead of opacity,\\n// set $hamburger-hover-use-filter as true and\\n// change the value of $hamburger-hover-filter accordingly.\\n$hamburger-hover-use-filter   : false !default;\\n$hamburger-hover-filter       : opacity(50%) !default;\\n$hamburger-active-hover-filter: $hamburger-hover-filter !default;\\n\\n// Types (Remove or comment out what you don’t need)\\n// ==================================================\\n$hamburger-types: (\\n  3dx,\\n  3dx-r,\\n  3dy,\\n  3dy-r,\\n  3dxy,\\n  3dxy-r,\\n  arrow,\\n  arrow-r,\\n  arrowalt,\\n  arrowalt-r,\\n  arrowturn,\\n  arrowturn-r,\\n  boring,\\n  collapse,\\n  collapse-r,\\n  elastic,\\n  elastic-r,\\n  emphatic,\\n  emphatic-r,\\n  minus,\\n  slider,\\n  slider-r,\\n  spin,\\n  spin-r,\\n  spring,\\n  spring-r,\\n  stand,\\n  stand-r,\\n  squeeze,\\n  vortex,\\n  vortex-r\\n) !default;\\n\\n// Base Hamburger (We need this)\\n// ==================================================\\n@import \\\"base\\\";\\n\\n// Hamburger types\\n// ==================================================\\n@import \\\"types/3dx\\\";\\n@import \\\"types/3dx-r\\\";\\n@import \\\"types/3dy\\\";\\n@import \\\"types/3dy-r\\\";\\n@import \\\"types/3dxy\\\";\\n@import \\\"types/3dxy-r\\\";\\n@import \\\"types/arrow\\\";\\n@import \\\"types/arrow-r\\\";\\n@import \\\"types/arrowalt\\\";\\n@import \\\"types/arrowalt-r\\\";\\n@import \\\"types/arrowturn\\\";\\n@import \\\"types/arrowturn-r\\\";\\n@import \\\"types/boring\\\";\\n@import \\\"types/collapse\\\";\\n@import \\\"types/collapse-r\\\";\\n@import \\\"types/elastic\\\";\\n@import \\\"types/elastic-r\\\";\\n@import \\\"types/emphatic\\\";\\n@import \\\"types/emphatic-r\\\";\\n@import \\\"types/minus\\\";\\n@import \\\"types/slider\\\";\\n@import \\\"types/slider-r\\\";\\n@import \\\"types/spin\\\";\\n@import \\\"types/spin-r\\\";\\n@import \\\"types/spring\\\";\\n@import \\\"types/spring-r\\\";\\n@import \\\"types/stand\\\";\\n@import \\\"types/stand-r\\\";\\n@import \\\"types/squeeze\\\";\\n@import \\\"types/vortex\\\";\\n@import \\\"types/vortex-r\\\";\\n\\n// ==================================================\\n// Cooking up additional types:\\n//\\n// The Sass for each hamburger type should be nested\\n// inside an @if directive to check whether or not\\n// it exists in $hamburger-types so only the CSS for\\n// included types are generated.\\n//\\n// e.g. hamburgers/types/_new-type.scss\\n//\\n// @if index($hamburger-types, new-type) {\\n//   .hamburger--new-type {\\n//     ...\\n//   }\\n// }\\n\",\"@use \\\"sass:math\\\";\\n\\n// Hamburger\\n// ==================================================\\n.hamburger {\\n  padding: $hamburger-padding-y $hamburger-padding-x;\\n  display: inline-block;\\n  cursor: pointer;\\n\\n  transition-property: opacity, filter;\\n  transition-duration: 0.15s;\\n  transition-timing-function: linear;\\n\\n  // Normalize (<button>)\\n  font: inherit;\\n  color: inherit;\\n  text-transform: none;\\n  background-color: transparent;\\n  border: 0;\\n  margin: 0;\\n  overflow: visible;\\n\\n  &:hover {\\n    @if $hamburger-hover-use-filter == true {\\n      filter: $hamburger-hover-filter;\\n    }\\n    @else {\\n      opacity: $hamburger-hover-opacity;\\n    }\\n  }\\n\\n  &.is-active {\\n    &:hover {\\n      @if $hamburger-hover-use-filter == true {\\n        filter: $hamburger-active-hover-filter;\\n      }\\n      @else {\\n        opacity: $hamburger-active-hover-opacity;\\n      }\\n    }\\n\\n    .hamburger-inner,\\n    .hamburger-inner::before,\\n    .hamburger-inner::after {\\n      background-color: $hamburger-active-layer-color;\\n    }\\n  }\\n}\\n\\n.hamburger-box {\\n  width: $hamburger-layer-width;\\n  height: $hamburger-layer-height * 3 + $hamburger-layer-spacing * 2;\\n  display: inline-block;\\n  position: relative;\\n}\\n\\n.hamburger-inner {\\n  display: block;\\n  top: 50%;\\n  margin-top: math.div($hamburger-layer-height, -2);\\n\\n  &,\\n  &::before,\\n  &::after {\\n    width: $hamburger-layer-width;\\n    height: $hamburger-layer-height;\\n    background-color: $hamburger-layer-color;\\n    border-radius: $hamburger-layer-border-radius;\\n    position: absolute;\\n    transition-property: transform;\\n    transition-duration: 0.15s;\\n    transition-timing-function: ease;\\n  }\\n\\n  &::before,\\n  &::after {\\n    content: \\\"\\\";\\n    display: block;\\n  }\\n\\n  &::before {\\n    top: ($hamburger-layer-spacing + $hamburger-layer-height) * -1;\\n  }\\n\\n  &::after {\\n    bottom: ($hamburger-layer-spacing + $hamburger-layer-height) * -1;\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dx) {\\n  /*\\n   * 3DX\\n   */\\n  .hamburger--3dx {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateY(180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dx-r) {\\n  /*\\n   * 3DX Reverse\\n   */\\n  .hamburger--3dx-r {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateY(-180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dy) {\\n  /*\\n   * 3DY\\n   */\\n  .hamburger--3dy {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateX(-180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dy-r) {\\n  /*\\n   * 3DY Reverse\\n   */\\n  .hamburger--3dy-r {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateX(180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dxy) {\\n  /*\\n   * 3DXY\\n   */\\n  .hamburger--3dxy {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateX(180deg) rotateY(180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dxy-r) {\\n  /*\\n   * 3DXY Reverse\\n   */\\n  .hamburger--3dxy-r {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateX(180deg) rotateY(180deg) rotateZ(-180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, arrow) {\\n  /*\\n   * Arrow\\n   */\\n  .hamburger--arrow.is-active {\\n    .hamburger-inner {\\n      &::before {\\n        transform: translate3d($hamburger-layer-width * -0.2, 0, 0) rotate(-45deg) scale(0.7, 1);\\n      }\\n\\n      &::after {\\n        transform: translate3d($hamburger-layer-width * -0.2, 0, 0) rotate(45deg) scale(0.7, 1);\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, arrow-r) {\\n  /*\\n   * Arrow Right\\n   */\\n  .hamburger--arrow-r.is-active {\\n    .hamburger-inner {\\n      &::before {\\n        transform: translate3d($hamburger-layer-width * 0.2, 0, 0) rotate(45deg) scale(0.7, 1);\\n      }\\n\\n      &::after {\\n        transform: translate3d($hamburger-layer-width * 0.2, 0, 0) rotate(-45deg) scale(0.7, 1);\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, arrowalt) {\\n  /*\\n   * Arrow Alt\\n   */\\n  .hamburger--arrowalt {\\n    .hamburger-inner {\\n      &::before {\\n        transition: top 0.1s 0.1s ease,\\n                    transform 0.1s cubic-bezier(0.165, 0.84, 0.44, 1);\\n      }\\n\\n      &::after {\\n        transition: bottom 0.1s 0.1s ease,\\n                    transform 0.1s cubic-bezier(0.165, 0.84, 0.44, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        &::before {\\n          top: 0;\\n          transform: translate3d($hamburger-layer-width * -0.2, $hamburger-layer-width * -0.25, 0) rotate(-45deg) scale(0.7, 1);\\n          transition: top 0.1s ease,\\n                      transform 0.1s 0.1s cubic-bezier(0.895, 0.03, 0.685, 0.22);\\n        }\\n\\n        &::after {\\n          bottom: 0;\\n          transform: translate3d($hamburger-layer-width * -0.2, $hamburger-layer-width * 0.25, 0) rotate(45deg) scale(0.7, 1);\\n          transition: bottom 0.1s ease,\\n                      transform 0.1s 0.1s cubic-bezier(0.895, 0.03, 0.685, 0.22);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, arrowalt-r) {\\n  /*\\n   * Arrow Alt Right\\n   */\\n  .hamburger--arrowalt-r {\\n    .hamburger-inner {\\n      &::before {\\n        transition: top 0.1s 0.1s ease,\\n                    transform 0.1s cubic-bezier(0.165, 0.84, 0.44, 1);\\n      }\\n\\n      &::after {\\n        transition: bottom 0.1s 0.1s ease,\\n                    transform 0.1s cubic-bezier(0.165, 0.84, 0.44, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        &::before {\\n          top: 0;\\n          transform: translate3d($hamburger-layer-width * 0.2, $hamburger-layer-width * -0.25, 0) rotate(45deg) scale(0.7, 1);\\n          transition: top 0.1s ease,\\n                      transform 0.1s 0.1s cubic-bezier(0.895, 0.03, 0.685, 0.22);\\n        }\\n\\n        &::after {\\n          bottom: 0;\\n          transform: translate3d($hamburger-layer-width * 0.2, $hamburger-layer-width * 0.25, 0) rotate(-45deg) scale(0.7, 1);\\n          transition: bottom 0.1s ease,\\n                      transform 0.1s 0.1s cubic-bezier(0.895, 0.03, 0.685, 0.22);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, arrowturn) {\\n  /*\\n   * Arrow Turn\\n   */\\n  .hamburger--arrowturn.is-active {\\n    .hamburger-inner {\\n      transform: rotate(-180deg);\\n\\n      &::before {\\n        transform: translate3d(8px, 0, 0) rotate(45deg) scale(0.7, 1);\\n      }\\n\\n      &::after {\\n        transform: translate3d(8px, 0, 0) rotate(-45deg) scale(0.7, 1);\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, arrowturn-r) {\\n  /*\\n   * Arrow Turn Right\\n   */\\n  .hamburger--arrowturn-r.is-active {\\n    .hamburger-inner {\\n      transform: rotate(-180deg);\\n\\n      &::before {\\n        transform: translate3d(-8px, 0, 0) rotate(-45deg) scale(0.7, 1);\\n      }\\n\\n      &::after {\\n        transform: translate3d(-8px, 0, 0) rotate(45deg) scale(0.7, 1);\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, boring) {\\n  /*\\n   * Boring\\n   */\\n  .hamburger--boring {\\n    .hamburger-inner {\\n      &,\\n      &::before,\\n      &::after {\\n        transition-property: none;\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        transform: rotate(45deg);\\n\\n        &::before {\\n          top: 0;\\n          opacity: 0;\\n        }\\n\\n        &::after {\\n          bottom: 0;\\n          transform: rotate(-90deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, collapse) {\\n  /*\\n   * Collapse\\n   */\\n  .hamburger--collapse {\\n    .hamburger-inner {\\n      top: auto;\\n      bottom: 0;\\n      transition-duration: 0.13s;\\n      transition-delay: 0.13s;\\n      transition-timing-function: cubic-bezier(0.55, 0.055, 0.675, 0.19);\\n\\n      &::after {\\n        top: ($hamburger-layer-spacing * 2 + $hamburger-layer-height * 2) * -1;\\n        transition: top 0.2s 0.2s cubic-bezier(0.33333, 0.66667, 0.66667, 1),\\n                    opacity 0.1s linear;\\n      }\\n\\n      &::before {\\n        transition: top 0.12s 0.2s cubic-bezier(0.33333, 0.66667, 0.66667, 1),\\n                    transform 0.13s cubic-bezier(0.55, 0.055, 0.675, 0.19);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        transform: translate3d(0, ($hamburger-layer-spacing + $hamburger-layer-height) * -1, 0) rotate(-45deg);\\n        transition-delay: 0.22s;\\n        transition-timing-function: cubic-bezier(0.215, 0.61, 0.355, 1);\\n\\n        &::after {\\n          top: 0;\\n          opacity: 0;\\n          transition: top 0.2s cubic-bezier(0.33333, 0, 0.66667, 0.33333),\\n                      opacity 0.1s 0.22s linear;\\n        }\\n\\n        &::before {\\n          top: 0;\\n          transform: rotate(-90deg);\\n          transition: top 0.1s 0.16s cubic-bezier(0.33333, 0, 0.66667, 0.33333),\\n                      transform 0.13s 0.25s cubic-bezier(0.215, 0.61, 0.355, 1);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, collapse-r) {\\n  /*\\n   * Collapse Reverse\\n   */\\n  .hamburger--collapse-r {\\n    .hamburger-inner {\\n      top: auto;\\n      bottom: 0;\\n      transition-duration: 0.13s;\\n      transition-delay: 0.13s;\\n      transition-timing-function: cubic-bezier(0.55, 0.055, 0.675, 0.19);\\n\\n      &::after {\\n        top: ($hamburger-layer-spacing * 2 + $hamburger-layer-height * 2) * -1;\\n        transition: top 0.2s 0.2s cubic-bezier(0.33333, 0.66667, 0.66667, 1),\\n                    opacity 0.1s linear;\\n      }\\n\\n      &::before {\\n        transition: top 0.12s 0.2s cubic-bezier(0.33333, 0.66667, 0.66667, 1),\\n                    transform 0.13s cubic-bezier(0.55, 0.055, 0.675, 0.19);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        transform: translate3d(0, ($hamburger-layer-spacing + $hamburger-layer-height) * -1, 0) rotate(45deg);\\n        transition-delay: 0.22s;\\n        transition-timing-function: cubic-bezier(0.215, 0.61, 0.355, 1);\\n\\n        &::after {\\n          top: 0;\\n          opacity: 0;\\n          transition: top 0.2s cubic-bezier(0.33333, 0, 0.66667, 0.33333),\\n                      opacity 0.1s 0.22s linear;\\n        }\\n\\n        &::before {\\n          top: 0;\\n          transform: rotate(90deg);\\n          transition: top 0.1s 0.16s cubic-bezier(0.33333, 0, 0.66667, 0.33333),\\n                      transform 0.13s 0.25s cubic-bezier(0.215, 0.61, 0.355, 1);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"sass:math\\\";\\n\\n@if index($hamburger-types, elastic) {\\n  /*\\n   * Elastic\\n   */\\n  .hamburger--elastic {\\n    .hamburger-inner {\\n      top: math.div($hamburger-layer-height, 2);\\n      transition-duration: 0.275s;\\n      transition-timing-function: cubic-bezier(0.68, -0.55, 0.265, 1.55);\\n\\n      &::before {\\n        top: $hamburger-layer-height + $hamburger-layer-spacing;\\n        transition: opacity 0.125s 0.275s ease;\\n      }\\n\\n      &::after {\\n        top: ($hamburger-layer-height * 2) + ($hamburger-layer-spacing * 2);\\n        transition: transform 0.275s cubic-bezier(0.68, -0.55, 0.265, 1.55);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        $y-offset: $hamburger-layer-spacing + $hamburger-layer-height;\\n\\n        transform: translate3d(0, $y-offset, 0) rotate(135deg);\\n        transition-delay: 0.075s;\\n\\n        &::before {\\n          transition-delay: 0s;\\n          opacity: 0;\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, $y-offset * -2, 0) rotate(-270deg);\\n          transition-delay: 0.075s;\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"sass:math\\\";\\n\\n@if index($hamburger-types, elastic-r) {\\n  /*\\n   * Elastic Reverse\\n   */\\n  .hamburger--elastic-r {\\n    .hamburger-inner {\\n      top: math.div($hamburger-layer-height, 2);\\n      transition-duration: 0.275s;\\n      transition-timing-function: cubic-bezier(0.68, -0.55, 0.265, 1.55);\\n\\n      &::before {\\n        top: $hamburger-layer-height + $hamburger-layer-spacing;\\n        transition: opacity 0.125s 0.275s ease;\\n      }\\n\\n      &::after {\\n        top: ($hamburger-layer-height * 2) + ($hamburger-layer-spacing * 2);\\n        transition: transform 0.275s cubic-bezier(0.68, -0.55, 0.265, 1.55);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        $y-offset: $hamburger-layer-spacing + $hamburger-layer-height;\\n\\n        transform: translate3d(0, $y-offset, 0) rotate(-135deg);\\n        transition-delay: 0.075s;\\n\\n        &::before {\\n          transition-delay: 0s;\\n          opacity: 0;\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, $y-offset * -2, 0) rotate(270deg);\\n          transition-delay: 0.075s;\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-type