\\\" as *;\\n@use \\\"base/footer.scss\\\" as *;\\n@use \\\"base/single-reference.scss\\\" as *;\\n\\n@use \\\"builder/header-service.scss\\\" as *;\\n@use \\\"builder/section-app-glob.scss\\\" as *;\\n@use \\\"builder/section-txt-g-img-d.scss\\\" as *;\\n@use \\\"builder/section-slider-vertical.scss\\\" as *;\\n@use \\\"builder/section-etapes.scss\\\" as *;\\n@use \\\"builder/section-parallax.scss\\\" as *;\\n@use \\\"builder/section-formulaire.scss\\\" as *;\\n\\n@use \\\"builder/header-service.scss\\\" as *;\\n@use \\\"builder/section-app-glob.scss\\\" as *;\\n@use \\\"builder/section-txt-g-img-d.scss\\\" as *;\\n@use \\\"builder/section-slider-vertical.scss\\\" as *;\\n@use \\\"builder/section-etapes.scss\\\" as *;\\n@use \\\"builder/section-parallax.scss\\\" as *;\\n@use \\\"builder/section-formulaire.scss\\\" as *;\\n@use \\\"builder/section-partenaire-sur-mesure\\\" as *;\\n\\nbody {\\n  font-family: \\\"Manrope\\\", sans-serif;\\n}\\n\\n@import \\\"./../../node_modules/hamburgers/_sass/hamburgers/hamburgers.scss\\\";\\n\",\"$primaryColor: #05233c;\\n$secondaryColor: #d3bea1;\\n\\n$txtColor: #222;\\n$lightGray: #e2e2e2;\\n$white: #fff;\\n$black: #000;\\n\\n/* Transparent */\\n$whiteTransparent: #ffffff00;\\n$lightGrayTransparent: #e2e2e270;\\n\",\"@use \\\"../variables/colors.scss\\\" as *;\\n\\n.container {\\n  width: 80vw;\\n  max-width: 1200px;\\n  margin: auto;\\n\\n  &.flex {\\n    display: flex;\\n\\n    @for $i from 1 through 100 {\\n      .col-#{$i} {\\n        width: $i * 1%;\\n      }\\n    }\\n  }\\n\\n  &.grid {\\n    display: grid;\\n  }\\n\\n  &.-large {\\n    width: 100vw;\\n    max-width: 100vw;\\n  }\\n}\\n\\n.big_title {\\n  color: $primaryColor;\\n  font-size: 4rem;\\n  line-height: 3.5rem;\\n}\\n\\n.block-img {\\n  img {\\n    width: 100%;\\n    height: 100%;\\n    object-fit: cover;\\n  }\\n}\\n\",\"@use \\\"./colors.scss\\\" as *;\\n\\n* {\\n  font-family: \\\"Manrope\\\", sans-serif;\\n}\\n\\nh2 {\\n  font-size: 3.5rem;\\n  line-height: 3.5rem;\\n}\\n\\np {\\n  font-size: 1rem;\\n  line-height: 1.8rem;\\n  font-weight: 100;\\n  font-weight: $txtColor;\\n\\n  & + p {\\n    margin-top: 1rem;\\n  }\\n}\\n\\nstrong {\\n  font-weight: 600;\\n}\\n\\n.section-label,\\n.surtitre {\\n  text-transform: uppercase;\\n  color: $secondaryColor;\\n  letter-spacing: 2px;\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n.btn-cta {\\n  display: flex;\\n  width: fit-content;\\n  align-items: center;\\n  color: $primaryColor;\\n  text-decoration: none;\\n  gap: 120px;\\n  text-decoration: none;\\n  font-size: 0.9rem;\\n  font-weight: 500;\\n  letter-spacing: 3px;\\n  text-transform: uppercase;\\n  padding-bottom: 6px;\\n  border-bottom: 1px solid $primaryColor;\\n  transition:\\n    gap 0.25s ease,\\n    border-color 0.25s ease;\\n\\n  &::after {\\n    content: \\\"\\\";\\n    background: url(\\\"./../../assets/images/arrow-right-gold.svg\\\");\\n    background-size: cover;\\n    font-size: 0.9rem;\\n    color: $secondaryColor;\\n    display: inline-block;\\n    width: 15px;\\n    height: 15px;\\n    margin-bottom: 3px;\\n    transform: rotate(45deg);\\n    transition: all ease-in 300ms;\\n  }\\n\\n  &:hover {\\n    border-bottom: 1px solid;\\n    color: $secondaryColor;\\n\\n    &::after {\\n      transform: rotate(0deg);\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.slider-fullwidth {\\n  position: relative;\\n  width: 100%;\\n  overflow: hidden;\\n}\\n\\n.swiper-fullwidth {\\n  width: 100%;\\n  height: 100vh;\\n\\n  .swiper-slide {\\n    position: relative;\\n    width: 100%;\\n    height: 100%;\\n    overflow: hidden;\\n\\n    .background {\\n      position: absolute;\\n      top: 0;\\n      left: 0;\\n      width: 100%;\\n      height: 100%;\\n      z-index: 0;\\n\\n      img {\\n        width: 100%;\\n        height: 100%;\\n        object-fit: cover;\\n        display: block;\\n      }\\n    }\\n\\n    .content {\\n      position: absolute;\\n      top: 20px;\\n      left: 10%;\\n      z-index: 1;\\n      max-width: 70%;\\n\\n      .content-titre {\\n        color: $white;\\n        font-size: 8rem;\\n        font-weight: 400;\\n        line-height: 1.2;\\n        margin-bottom: 30px;\\n        padding-top: 500px;\\n        padding-left: 100px;\\n      }\\n\\n      .btn-cta {\\n        display: inline-block;\\n        color: $white;\\n        border-bottom: 1px solid $lightGray;\\n        margin-left: 220px;\\n      } \\n\\n    }\\n  }\\n\\n  .block-pagination {\\n    position: absolute;\\n    bottom: 0;\\n    right: 0;\\n    z-index: 2;\\n    background-color: $white;\\n    width: clamp(220px, 26vw, 400px);\\n    height: 90px;\\n    padding: 0 28px;\\n    display: flex;\\n    align-items: center;\\n    justify-content: space-between;\\n    gap: 20px;\\n\\n    .block-scrollbar {\\n      display: flex;\\n      align-items: center;\\n      gap: 10px;\\n      flex: 1;\\n\\n      .number-slide {\\n        font-size: 0.72rem;\\n        font-weight: 500;\\n        letter-spacing: 0.08em;\\n        color: $primaryColor;\\n        min-width: 18px;\\n      }\\n\\n      .swiper-scrollbar {\\n        flex: 1;\\n        height: 1px;\\n        background-color: $lightGray;\\n        border-radius: 0;\\n        position: relative;\\n        top: auto;\\n        left: auto;\\n\\n        .swiper-scrollbar-drag {\\n          height: 100%;\\n          background-color: $primaryColor;\\n          border-radius: 0;\\n          cursor: pointer;\\n        }\\n      }\\n    }\\n\\n    .swiper-pagination {\\n      position: relative;\\n      display: flex;\\n      align-items: center;\\n      gap: 6px;\\n      flex-shrink: 0;\\n      width: auto;\\n\\n      .swiper-pagination-bullet {\\n        width: 7px;\\n        height: 7px;\\n        background-color: $lightGray;\\n        opacity: 1;\\n        margin: 0;\\n        transition: background-color 0.25s ease;\\n      }\\n\\n      .swiper-pagination-bullet-active {\\n        background-color: $primaryColor;\\n      }\\n    }\\n  }\\n}\\n\\n// Responsive\\n\\n@media (max-width: 1024px) {\\n  .swiper-fullwidth {\\n    .swiper-slide .content {\\n      left: 7%;\\n      max-width: 75%;\\n    }\\n  }\\n}\\n\\n@media (max-width: 768px) {\\n  .swiper-fullwidth {\\n    .swiper-slide .content {\\n      left: 5%;\\n      bottom: 90px;\\n      max-width: 90%;\\n    }\\n\\n    .block-pagination {\\n      width: 100%;\\n      height: 72px;\\n      padding: 0 20px;\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.section-text-evidence {\\n  background-color: $white;\\n  padding: 90px 0;\\n  margin-top: 100px;\\n\\n  .section-label {\\n    display: flex;\\n    align-items: center;\\n    gap: 16px;\\n    margin-bottom: 36px;\\n\\n    span {\\n      font-size: 0.9rem;\\n      font-weight: 500;\\n      text-transform: uppercase;\\n      color: $primaryColor;\\n    }\\n\\n    &::after {\\n      content: \\\"\\\";\\n      display: block;\\n      height: 1px;\\n      width: 60px;\\n      background-color: $primaryColor;\\n      opacity: 0.4;\\n    }\\n  }\\n}\\n\\n.section-content {\\n  margin-bottom: 40px;\\n\\n  p {\\n    font-size: 4rem;\\n    line-height: 4rem;\\n  }\\n}\\n\\n.section-paragraph {\\n  margin-top: 20px;\\n  color: $txtColor;\\n\\n  p {\\n    font-size: 4rem;\\n    line-height: 4rem;\\n  }\\n}\\n\\n@media (max-width: 1024px) {\\n  .section-text-evidence .section-inner {\\n    max-width: 80%;\\n  }\\n}\\n\\n@media (max-width: 768px) {\\n  .section-text-evidence {\\n    padding: 60px 0;\\n\\n    .section-inner {\\n      margin: 0;\\n      max-width: 90%;\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.section-card-solutions {\\n  background-color: $white;\\n  padding: 80px;\\n  margin-top: 100px;\\n\\n  .cards-grid {\\n    display: grid;\\n    grid-template-columns: repeat(3, 1fr);\\n    gap: 30px;\\n    padding-bottom: 100px;\\n    border-bottom: 1px solid $lightGray;\\n  }\\n\\n  .card {\\n    display: flex;\\n    flex-direction: column;\\n    cursor: pointer;\\n    max-height: 600px;\\n  }\\n\\n  .card-image {\\n    position: relative;\\n    width: 100%;\\n    aspect-ratio: 4 / 5;\\n    max-height: 500px;\\n    background-color: $lightGray;\\n\\n    img {\\n      width: 100%;\\n      height: 100%;\\n      object-fit: cover;\\n      display: block;\\n    }\\n\\n    .card-plus {\\n      position: absolute;\\n      bottom: -1px;\\n      right: -1px;\\n      width: 80px;\\n      height: 80px;\\n      background-color: $white;\\n      color: $primaryColor;\\n      font-size: 2rem;\\n      font-weight: 300;\\n      display: flex;\\n      align-items: center;\\n      justify-content: center;\\n      text-decoration: none;\\n      transition:\\n        background-color 0.25s ease,\\n        color 0.25s ease;\\n\\n      &:hover {\\n        background-color: $primaryColor;\\n        color: $white;\\n      }\\n    }\\n  }\\n\\n  .card-body {\\n    padding-top: 18px;\\n    display: flex;\\n    flex-direction: column;\\n    gap: 8px;\\n  }\\n\\n  .card-category {\\n    font-size: 1rem;\\n    font-weight: 500;\\n    letter-spacing: 1px;\\n    text-transform: uppercase;\\n    color: $secondaryColor;\\n  }\\n\\n  .card-title {\\n    font-size: 1.2rem;\\n    letter-spacing: 5px;\\n    font-weight: 500;\\n    text-transform: uppercase;\\n    color: $primaryColor;\\n    margin: 0;\\n  }\\n}\\n\\n// Responsive\\n@media (max-width: 1024px) {\\n  .section-card-solutions {\\n    padding: 60px;\\n\\n    .cards-grid {\\n      gap: 20px;\\n    }\\n  }\\n}\\n\\n@media (max-width: 768px) {\\n  .section-card-solutions {\\n    padding: 50px;\\n\\n    .cards-grid {\\n      grid-template-columns: 100%;\\n      gap: 32px;\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.section-two-col {\\n  background-color: $white;\\n  padding: 100px 0;\\n\\n  .two-col-inner {\\n    gap: 80px;\\n    align-items: start;\\n\\n    .two-col-left {\\n      .section-label {\\n        display: flex;\\n        align-items: center;\\n        gap: 16px;\\n        margin-bottom: 28px;\\n\\n        span {\\n          font-size: 1rem;\\n          font-weight: 500;\\n          text-transform: uppercase;\\n          color: $primaryColor;\\n        }\\n\\n        .two-col-left {\\n          .section-label {\\n            display: flex;\\n            align-items: center;\\n            gap: 16px;\\n            margin-bottom: 28px;\\n\\n            .two-col-title {\\n              font-size: 4rem;\\n              line-height: 1.2;\\n              max-width: 550px;\\n            }\\n          }\\n\\n          &::after {\\n            content: \\\"\\\";\\n            display: block;\\n            height: 1px;\\n            width: 60px;\\n            background-color: $primaryColor;\\n            opacity: 0.4;\\n          }\\n        }\\n      }\\n\\n      .two-col-details,\\n      .two-col-paragraph {\\n        font-size: 1rem;\\n        line-height: 1.8;\\n        color: $txtColor;\\n\\n        p {\\n          margin: 0;\\n        }\\n      }\\n    }\\n  }\\n}\\n\\n// ── Responsive\\n\\n@media (max-width: 1024px) {\\n  .section-two-col .two-col-inner {\\n    grid-template-columns: 100%;\\n    gap: 48px;\\n    margin: 0;\\n  }\\n}\\n\\n@media (max-width: 768px) {\\n  .section-two-col {\\n    padding: 60px 0;\\n\\n    .two-col-inner {\\n      grid-template-columns: 100%;\\n      gap: 32px;\\n      margin: 0 5%;\\n    }\\n\\n    .two-col-right {\\n      padding-top: 0;\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.section-gallery {\\n  position: relative;\\n  padding: 100px 0;\\n  background-color: $white;\\n}\\n\\n.swiper-gallery {\\n  width: 100%;\\n  overflow: hidden;\\n  position: relative;\\n\\n  .swiper-slide {\\n    .gallery-slide-inner {\\n      position: relative;\\n    }\\n\\n    .gallery-image {\\n      width: 100%;\\n      max-height: 100vh;\\n      aspect-ratio: 4 / 3;\\n      background-color: $lightGray;\\n\\n      img {\\n      