n}\\n\\nstrong {\\n  font-weight: 600;\\n}\\n\\n.section-label,\\n.surtitre {\\n  text-transform: uppercase;\\n  color: $secondaryColor;\\n  letter-spacing: 2px;\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n.btn-cta {\\n  display: flex;\\n  width: fit-content;\\n  align-items: center;\\n  color: $primaryColor;\\n  text-decoration: none;\\n  gap: 120px;\\n  text-decoration: none;\\n  font-size: 0.9rem;\\n  font-weight: 500;\\n  letter-spacing: 3px;\\n  text-transform: uppercase;\\n  padding-bottom: 6px;\\n  border-bottom: 1px solid $primaryColor;\\n  transition:\\n    gap 0.25s ease,\\n    border-color 0.25s ease;\\n\\n  &::after {\\n    content: \\\"\\\";\\n    background: url(\\\"./../../assets/images/arrow-right-gold.svg\\\");\\n    background-size: cover;\\n    font-size: 0.9rem;\\n    color: $secondaryColor;\\n    display: inline-block;\\n    width: 15px;\\n    height: 15px;\\n    margin-bottom: 3px;\\n    transform: rotate(45deg);\\n    transition: all ease-in 300ms;\\n  }\\n\\n  &:hover {\\n    border-bottom: 1px solid;\\n    color: $secondaryColor;\\n\\n    &::after {\\n      transform: rotate(0deg);\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.site-header {\\n  width: 100%;\\n  z-index: 100;\\n  padding: 30px 40px;\\n  position: relative;\\n\\n  .header-inner {\\n    display: flex;\\n    align-items: center;\\n    justify-content: space-between;\\n    gap: 40px;\\n\\n    .header-logo {\\n      flex-shrink: 0;\\n      width: 300px;\\n      display: block;\\n\\n      img {\\n        width: 100%;\\n        height: auto;\\n        display: block;\\n      }\\n    }\\n\\n    .header-nav {\\n      flex: 1;\\n      display: flex;\\n      justify-content: flex-end;\\n\\n      .navbar {\\n        list-style: none;\\n        display: flex;\\n        align-items: center;\\n        gap: 40px;\\n        margin: 0;\\n        padding: 0;\\n\\n        > li {\\n          position: relative;\\n\\n          > a {\\n            color: $primaryColor;\\n            text-decoration: none;\\n            font-size: 0.8rem;\\n            letter-spacing: 1px;\\n            text-transform: uppercase;\\n            white-space: nowrap;\\n            display: flex;\\n            align-items: center;\\n            gap: 6px;\\n            transition: opacity 0.2s ease;\\n\\n            &:hover {\\n              opacity: 0.7;\\n            }\\n          }\\n\\n          &.menu-item-has-children {\\n            > a::after {\\n              content: \\\"\\\";\\n              display: inline-block;\\n              width: 0;\\n              height: 0;\\n              border-left: 4px solid transparent;\\n              border-right: 4px solid transparent;\\n              border-top: 5px solid $white;\\n              margin-top: 2px;\\n              transition: transform 0.2s ease;\\n            }\\n\\n            .sub-menu {\\n              position: absolute;\\n              top: calc(100% + 20px);\\n              left: 0;\\n              background-color: rgba(255, 255, 255, 0.6);\\n              min-width: 220px;\\n              list-style: none;\\n              padding: 0;\\n              margin: 0;\\n              opacity: 0;\\n              visibility: hidden;\\n              transform: translateY(-6px);\\n              transition:\\n                opacity 0.25s ease,\\n                transform 0.25s ease,\\n                visibility 0.25s;\\n\\n              li {\\n                a {\\n                  display: block;\\n                  padding: 12px 20px;\\n                  font-size: 0.75rem;\\n                  letter-spacing: 0.08em;\\n                  color: $primaryColor;\\n                  text-decoration: none;\\n                  border-bottom: 1px solid $lightGray;\\n                  transition: color 0.2s ease;\\n\\n                  &:hover {\\n                    color: $secondaryColor;\\n                  }\\n                }\\n\\n                &:last-child a {\\n                  border-bottom: none;\\n                }\\n              }\\n            }\\n\\n            &:hover {\\n              > a::after {\\n                transform: rotate(180deg);\\n              }\\n\\n              .sub-menu {\\n                opacity: 1;\\n                visibility: visible;\\n                transform: translateY(0);\\n              }\\n            }\\n          }\\n        }\\n      }\\n    }\\n  }\\n\\n  .header-actions {\\n    display: flex;\\n    align-items: center;\\n    gap: 30px;\\n    flex-shrink: 0;\\n\\n    .header-separator {\\n      display: block;\\n      width: 1px;\\n      height: 36px;\\n      background-color: rgba(255, 255, 255, 0.4);\\n    }\\n\\n    .burger-btn {\\n      background: none;\\n      border: none;\\n      cursor: pointer;\\n      padding: 4px;\\n      display: flex;\\n      flex-direction: column;\\n      gap: 6px;\\n\\n      span {\\n        display: block;\\n        width: 28px;\\n        height: 1.5px;\\n        background-color: $primaryColor;\\n        transition:\\n          transform 0.3s ease,\\n          opacity 0.3s ease;\\n\\n        &:last-child {\\n          width: 18px;\\n        }\\n      }\\n\\n      &.is-active {\\n        span {\\n          background-color: $white;\\n        }\\n\\n        span:nth-child(1) {\\n          transform: translateY(7.5px) rotate(45deg);\\n        }\\n        span:nth-child(2) {\\n          opacity: 0;\\n        }\\n        span:nth-child(3) {\\n          transform: translateY(-7.5px) rotate(-45deg);\\n          width: 28px;\\n        }\\n      }\\n    }\\n  }\\n\\n  &.-frontpage {\\n    position: absolute;\\n    top: 0;\\n    left: 0;\\n\\n    .header-inner {\\n      .header-nav {\\n        .navbar {\\n          > li {\\n            > a {\\n              color: $white;\\n            }\\n          }\\n        }\\n      }\\n    }\\n\\n    .header-actions {\\n      .burger-btn {\\n        span {\\n          background-color: $white;\\n        }\\n      }\\n    }\\n  }\\n}\\n\\n.mobile-menu {\\n  position: fixed;\\n  inset: 0;\\n  background-color: $primaryColor;\\n  z-index: 99;\\n  display: flex;\\n  align-items: center;\\n  justify-content: center;\\n  opacity: 0;\\n  visibility: hidden;\\n  transform: translateX(100%);\\n  transition:\\n    transform 0.4s ease,\\n    opacity 0.3s ease,\\n    visibility 0.4s;\\n  height: 100vh;\\n\\n  &.is-open {\\n    opacity: 1;\\n    visibility: visible;\\n    transform: translateX(0);\\n  }\\n\\n  .mobile-navbar {\\n    list-style: none;\\n    padding: 0;\\n    margin: 0;\\n    text-align: center;\\n\\n    > li {\\n      padding: 16px 0;\\n\\n      > a {\\n        color: $white;\\n        text-decoration: none;\\n        font-size: 1.4rem;\\n        letter-spacing: 0.12em;\\n        text-transform: uppercase;\\n        transition: color 0.2s ease;\\n\\n        &:hover {\\n          color: $secondaryColor;\\n        }\\n      }\\n\\n      .sub-menu {\\n        list-style: none;\\n        padding: 10px 0 0;\\n        margin: 0;\\n\\n        li {\\n          padding: 6px 0;\\n\\n          a {\\n            font-size: 0.95rem;\\n            color: rgba(255, 255, 255, 0.6);\\n            text-decoration: none;\\n            letter-spacing: 0.06em;\\n            transition: color 0.2s ease;\\n\\n            &:hover {\\n              color: $white;\\n            }\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n\\n// Responsive\\n\\n@media (max-width: 768px) {\\n  .site-header {\\n    padding: 20px;\\n  }\\n\\n  .header-nav {\\n    display: none;\\n  }\\n\\n  .header-separator {\\n    display: none;\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.site-footer {\\n    background-color: $primaryColor;\\n    padding: 150px;\\n    position: relative;\\n    margin-top: 100px;\\n\\n    .footer-top {\\n        display: flex;\\n        justify-content: space-between;\\n        align-items: flex-start;\\n        margin-bottom: 60px;\\n\\n        .footer-left {\\n            width: 50%;\\n            display: flex;\\n            flex-direction: column;\\n            gap: 40px;\\n\\n            .footer-titre {\\n                color: $white;\\n                font-size: 4rem;\\n                font-weight: 700;\\n                line-height: 1.1;\\n            }\\n\\n            .footer-arrow {\\n                width: 40px;\\n                height: 40px;\\n                color: $secondaryColor;\\n                stroke: $secondaryColor;\\n                margin-left: 300px;\\n           \\n            }\\n\\n            \\n        }\\n\\n        .footer-right {\\n            width: 40%;\\n            padding-top: 80px;\\n\\n            .footer-texte {\\n                p{\\n                    color: $white;\\n                    font-size: 1rem;\\n                    line-height: 1.7;\\n                }\\n            }\\n        }\\n    }\\n\\n    .footer-lien {\\n        width: fit-content;\\n        display: block;\\n                color: $white;\\n                text-decoration: none;\\n                font-size: 1.5rem;\\n                letter-spacing: 0.05em;\\n                margin: 20px auto;\\n                text-align: center;\\n\\n                &:hover {\\n                    text-decoration: underline;\\n                }\\n            }\\n\\n    .footer-bottom {\\n        display: flex;\\n        justify-content: space-between;\\n        align-items: center;\\n        border-top: 0.5px solid $white;\\n        padding-top: 30px;\\n\\n        .footer-made-by {\\n            p{   \\n                color: $white;\\n            font-size: 0.9rem;\\n        \\n        \\n        }\\n         \\n        }\\n\\n        .footer-nav {\\n            display: flex;\\n            gap: 30px;\\n            list-style: none;\\n            margin: 0;\\n            padding: 0;\\n\\n            li a {\\n               color: $white;\\n                text-decoration: none;\\n                font-size: 0.7rem;\\n                letter-spacing: 0.15em;\\n                text-transform: uppercase;\\n\\n                &:hover {\\n                    color: $secondaryColor;\\n                }\\n            }\\n        }\\n    }\\n}\\n\\n.scroll-top {\\nposition: fixed;\\nbottom: 30px;\\nright: 30px;\\nwidth: 44px;\\nheight: 44px;\\nbackground-color: $secondaryColor;\\ncolor: $white;\\ndisplay: flex;\\nalign-items: center;\\njustify-content: center;\\ntext-decoration: none;\\nfont-size: 2rem;\\nz-index: 100;\\nopacity: 0;\\nvisibility: hidden;\\ntransition: opacity 0.3s;\\n&.visible {\\nopacity: 1;\\nvisibility: visible;\\n    }\\n}\",\".galerie-reference {\\n  .swiper-reference {\\n    height: 90vh;\\n\\n    .swiper-slide {\\n      img {\\n        object-fit: cover;\\n        width: 100%;\\n        height: 100%;\\n      }\\n    }\\n  }\\n}\\n\\n.bloc-reference {\\n  padding-top: 150px;\\n\\n  .container {\\n    gap: 100px;\\n\\n    .col-g {\\n      .block-img {\\n        height: 600px;\\n        max-height: 700px;\\n        width: 100%;\\n      }\\n    }\\n\\n    .col-d {\\n      .section-informations {\\n        padding: 0 100px 100px;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 20px;\\n\\n        p {\\n          font-weight: 200;\\n\\n          strong {\\n            font-weight: 400;\\n          }\\n        }\\n      }\\n\\n      .block-img {\\n        height: 800px;\\n        max-height: 900px;\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.section-service-header {\\n  margin-top: -200px;\\n  background-color: $primaryColor;\\n  height: 30vh;\\n  width: 100vw;\\n  min-height: 500px;\\n  display: flex;\\n  align-items: flex-end;\\n  justify-content: flex-end;\\n\\n  .container {\\n    margin: 0;\\n    align-items: flex-end;\\n    justify-content: space-between;\\n    width: 90vw;\\n    max-width: 1400px;\\n\\n    .colg {\\n      h1 {\\n        color: $white;\\n        font-size: 7rem;\\n        line-height: 5rem;\\n        font-weight: 700;\\n      }\\n    }\\n\\n    .cold {\\n      .block-cta {\\n        background-color: #fff;\\n        height: 60px;\\n        width: 400px;\\n        display: flex;\\n        align-items: flex-end;\\n        justify-content: center;\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.section-actu {\\n  background-color: $white;\\n  padding: 80px 0;\\n  margin-top: 100px;\\n\\n  .actu-title {\\n    color: $primaryColor;\\n    font-size: 2rem;\\n    font-weight: 300;\\n    text-align: center;\\n    margin-bottom: 50px;\\n\\n    strong {\\n      font-weight: 700;\\n    }\\n  }\\n\\n  .actu-grid {\\n    display: grid;\\n    grid-template-columns: repeat(4, 1fr);\\n    gap: 30px;\\n    margin-bottom: 50px;\\n    align-items: start;\\n  }\\n\\n  .actu-card {\\n    .actu-card-img {\\n      position: relative;\\n      background-color: $lightGray;\\n      height: 250px;\\n      overflow: hidden;\\n      margin-bottom: 15px;\\n      cursor: pointer;\\n\\n      img {\\n        width: 100%;\\n        height: 100%;\\n        object-fit: cover;\\n        display: block;\\n      }\\n\\n      .actu-card-plus {\\n        position: absolute;\\n        bottom: 0;\\n        right: 0;\\n        width: 50px;\\n        height: 50px;\\n        background-color: $white;\\n        color: $primaryColor;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-size: 1.2rem;\\n        text-decoration: none;\\n      }\\n    }\\n\\n    .actu-card-cat {\\n      display: block;\\n      font-size: 0.65rem;\\n      letter-spacing: 0.15em;\\n      text-transform: uppercase;\\n      color: $secondaryColor;\\n      margin-bottom: 10px;\\n      cursor: pointer;\\n    }\\n\\n    .actu-card-text {\\n      font-size: 0.9rem;\\n      line-height: 1.6;\\n      color: $txtColor;\\n      cursor: pointer;\\n    }\\n\\n    &:first-child {\\n      grid-column: span 2;\\n    }\\n  }\\n\\n  .actu-btn-wrap {\\n    display: flex;\\n    justify-content: center;\\n\\n    .actu-btn {\\n      display: inline-block;\\n      background-color: $primaryColor;\\n      color: $white;\\n      text-decoration: none;\\n      font-size: 0.7rem;\\n      letter-spacing: 0.2em;\\n      text-transform: uppercase;\\n      padding-top: 16px;\\n      padding-bottom: 16px;\\n      padding-left: 40px;\\n      padding-right: 40px;\\n    }\\n  }\\n}\\n\\n@media (max-width: 1024px) {\\n  .section-actu .actu-grid {\\n    grid-template-columns: repeat(2, 1fr);\\n  }\\n}\\n\\n@media (max-width: 768px) {\\n  .section-actu {\\n    padding-top: 50px;\\n    padding-bottom: 50px;\\n    padding-left: 5%;\\n    padding-right: 5%;\\n\\n    .actu-grid {\\n      grid-template-columns: 1fr;\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/base.scss\\\" as *;\\n@use \\\"./../variables/colors.scss\\\" as *;\\n@use \\\"./../variables/fonts.scss\\\" as *;\\n@use \\\"./../variables/cta.scss\\\" as *;\\n\\n.section-approche-globale {\\n  padding: 100px 0;\\n\\n  .container {\\n    h2 {\\n      font-size: 5rem;\\n      line-height: 4.5rem;\\n      margin: 30px 0;\\n      color: $primaryColor;\\n    }\\n\\n    &.grid {\\n      grid-template-columns: repeat(4, 1fr);\\n      gap: 20px;\\n      margin: 50px auto;\\n\\n      .card {\\n        aspect-ratio: 1;\\n        padding: 30px;\\n        border: 1px solid $lightGray;\\n        display: flex;\\n        align-items: flex-end;\\n        justify-content: flex-start;\\n\\n        .content-card {\\n          max-width: 50%;\\n          display: flex;\\n          flex-direction: column;\\n          gap: 20px;\\n\\n          .block-img {\\n            width: 60px;\\n            height: 60px;\\n          }\\n\\n          h3 {\\n            font-weight: 500;\\n            color: $primaryColor;\\n          }\\n\\n          .btn-cta {\\n            text-decoration: none;\\n            border-bottom: none;\\n          }\\n        }\\n      }\\n    }\\n\\n    .btn-cta {\\n      &.section {\\n        background-color: $secondaryColor;\\n        color: $white;\\n        padding: 15px 50px;\\n        border-bottom: none;\\n        margin: auto;\\n        transition: all ease-in 200ms;\\n\\n        &::after {\\n          color: $white;\\n        }\\n\\n        &:hover {\\n          background-color: $primaryColor;\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.section-card-solutions {\\n  background-color: $white;\\n  padding: 80px;\\n  margin-top: 100px;\\n\\n  .cards-grid {\\n    display: grid;\\n    grid-template-columns: repeat(3, 1fr);\\n    gap: 30px;\\n    padding-bottom: 100px;\\n    border-bottom: 1px solid $lightGray;\\n  }\\n\\n  .card {\\n    display: flex;\\n    flex-direction: column;\\n    cursor: pointer;\\n    max-height: 600px;\\n  }\\n\\n  .card-image {\\n    position: relative;\\n    width: 100%;\\n    aspect-ratio: 4 / 5;\\n    max-height: 500px;\\n    background-color: $lightGray;\\n\\n    img {\\n      width: 100%;\\n      height: 100%;\\n      object-fit: cover;\\n      display: block;\\n    }\\n\\n    .card-plus {\\n      position: absolute;\\n      bottom: -1px;\\n      right: -1px;\\n      width: 80px;\\n      height: 80px;\\n      background-color: $white;\\n      color: $primaryColor;\\n      font-size: 2rem;\\n      font-weight: 300;\\n      display: flex;\\n      align-items: center;\\n      justify-content: center;\\n      text-decoration: none;\\n      transition:\\n        background-color 0.25s ease,\\n        color 0.25s ease;\\n\\n      &:hover {\\n        background-color: $primaryColor;\\n        color: $white;\\n      }\\n    }\\n  }\\n\\n  .card-body {\\n    padding-top: 18px;\\n    display: flex;\\n    flex-direction: column;\\n    gap: 8px;\\n  }\\n\\n  .card-category {\\n    font-size: 1rem;\\n    font-weight: 500;\\n    letter-spacing: 1px;\\n    text-transform: uppercase;\\n    color: $secondaryColor;\\n  }\\n\\n  .card-title {\\n    font-size: 1.2rem;\\n    