width {\\n  position: relative;\\n  width: 100%;\\n  overflow: hidden;\\n}\\n\\n.swiper-fullwidth {\\n  width: 100%;\\n  height: 100vh;\\n\\n  .swiper-slide {\\n    position: relative;\\n    width: 100%;\\n    height: 100%;\\n    overflow: hidden;\\n\\n    .background {\\n      position: absolute;\\n      top: 0;\\n      left: 0;\\n      width: 100%;\\n      height: 100%;\\n      z-index: 0;\\n\\n      img {\\n        width: 100%;\\n        height: 100%;\\n        object-fit: cover;\\n        display: block;\\n      }\\n    }\\n\\n    .content {\\n      position: absolute;\\n      top: 20px;\\n      left: 10%;\\n      z-index: 1;\\n      max-width: 70%;\\n\\n      .content-titre {\\n        color: $white;\\n        font-size: 8rem;\\n        font-weight: 400;\\n        line-height: 1.2;\\n        margin-bottom: 30px;\\n        padding-top: 500px;\\n        padding-left: 100px;\\n      }\\n\\n      .btn-cta {\\n        display: inline-block;\\n        color: $white;\\n        border-bottom: 1px solid $lightGray;\\n        margin-left: 220px;\\n      } \\n\\n    }\\n  }\\n\\n  .block-pagination {\\n    position: absolute;\\n    bottom: 0;\\n    right: 0;\\n    z-index: 2;\\n    background-color: $white;\\n    width: clamp(220px, 26vw, 400px);\\n    height: 90px;\\n    padding: 0 28px;\\n    display: flex;\\n    align-items: center;\\n    justify-content: space-between;\\n    gap: 20px;\\n\\n    .block-scrollbar {\\n      display: flex;\\n      align-items: center;\\n      gap: 10px;\\n      flex: 1;\\n\\n      .number-slide {\\n        font-size: 0.72rem;\\n        font-weight: 500;\\n        letter-spacing: 0.08em;\\n        color: $primaryColor;\\n        min-width: 18px;\\n      }\\n\\n      .swiper-scrollbar {\\n        flex: 1;\\n        height: 1px;\\n        background-color: $lightGray;\\n        border-radius: 0;\\n        position: relative;\\n        top: auto;\\n        left: auto;\\n\\n        .swiper-scrollbar-drag {\\n          height: 100%;\\n          background-color: $primaryColor;\\n          border-radius: 0;\\n          cursor: pointer;\\n        }\\n      }\\n    }\\n\\n    .swiper-pagination {\\n      position: relative;\\n      display: flex;\\n      align-items: center;\\n      gap: 6px;\\n      flex-shrink: 0;\\n      width: auto;\\n\\n      .swiper-pagination-bullet {\\n        width: 7px;\\n        height: 7px;\\n        background-color: $lightGray;\\n        opacity: 1;\\n        margin: 0;\\n        transition: background-color 0.25s ease;\\n      }\\n\\n      .swiper-pagination-bullet-active {\\n        background-color: $primaryColor;\\n      }\\n    }\\n  }\\n}\\n\\n// Responsive\\n\\n@media (max-width: 1024px) {\\n  .swiper-fullwidth {\\n    .swiper-slide .content {\\n      left: 7%;\\n      max-width: 75%;\\n    }\\n  }\\n}\\n\\n@media (max-width: 768px) {\\n  .swiper-fullwidth {\\n    .swiper-slide .content {\\n      left: 5%;\\n      bottom: 90px;\\n      max-width: 90%;\\n    }\\n\\n    .block-pagination {\\n      width: 100%;\\n      height: 72px;\\n      padding: 0 20px;\\n    }\\n  }\\n}\\n\",\"@use \\\"./../variables/colors.scss\\\" as *;\\n\\n.menu-burger {\\n  display: flex;\\n  width: 100%;\\n  height: 100vh;\\n  gap: 10px;\\n  align-items: flex-end;\\n  justify-content: space-between;\\n\\n  /* Colonne gauche */\\n\\n  .menu-burger-left {\\n    width: 50%;\\n    position: relative;\\n    display: flex;\\n    align-items: flex-end;\\n    height: 100%;\\n\\n    img {\\n      position: absolute;\\n      object-fit: cover;\\n      z-index: 1;\\n      width: 100%;\\n      height: 100%;\\n      filter: brightness(0.5);\\n    }\\n\\n    .menu-burger-left-bottom {\\n      position: absolute;\\n      z-index: 1;\\n      display: flex;\\n      flex-direction: column;\\n      gap: 20px;\\n      bottom: 80px;\\n      padding-left: 5vw;\\n\\n      .menu-burger-contact {\\n        color: $white;\\n        font-size: 3rem;\\n        font-weight: 300;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 20px;\\n\\n        .menu-burger-contact-name {\\n          text-transform: uppercase;\\n          font-weight: 600;\\n          letter-spacing: 1px;\\n        }\\n\\n        .contact-adresse,\\n        .contact-tel-mail {\\n          p,\\n          p + p {\\n            margin-top: 0;\\n            line-height: 1.5rem;\\n          }\\n        }\\n      }\\n\\n      .menu-burger-socials {\\n        display: flex;\\n        gap: 5px;\\n        align-items: center;\\n        justify-items: center;\\n        margin-top: 50px;\\n\\n        a {\\n          width: 20px;\\n          height: 20px;\\n          display: block;\\n\\n          img {\\n            width: 100%;\\n            height: 100%;\\n            object-fit: contain;\\n            position: relative;\\n            filter: none;\\n          }\\n        }\\n      }\\n    }\\n  }\\n\\n  /* Colonne droite */\\n\\n  .menu-burger-right {\\n    width: 50%;\\n    background-color: $primaryColor;\\n    display: flex;\\n    flex-direction: column;\\n    justify-content: center;\\n    align-items: flex-end;\\n    padding-bottom: 80px;\\n    padding-right: 50px;\\n    gap: 150px;\\n    height: fit-content;\\n\\n    .burger-nav {\\n      width: 100%;\\n\\n      .burger-menu_list {\\n        display: flex;\\n        flex-direction: column;\\n        gap: 10px;\\n\\n        li {\\n          color: $white;\\n          text-transform: uppercase;\\n          letter-spacing: 2px;\\n          display: block;\\n          text-decoration: none;\\n          width: 100%;\\n          text-align: right;\\n\\n          a {\\n            display: flex;\\n            gap: 20px;\\n            justify-content: flex-end;\\n            align-items: flex-end;\\n          }\\n\\n          &.big-menu {\\n            font-size: 2.5rem;\\n            font-weight: 600;\\n            line-height: 3rem;\\n\\n            a {\\n              line-height: 2.5rem;\\n            }\\n          }\\n\\n          &.bg-menu-small {\\n            font-size: 2rem;\\n            font-weight: 300;\\n            line-height: 2.5rem;\\n\\n            a {\\n              line-height: 2rem;\\n            }\\n          }\\n\\n          &.bg-menu-gold {\\n            color: $secondaryColor;\\n            font-size: 1.5rem;\\n\\n            a {\\n              line-height: 1.5rem;\\n            }\\n          }\\n        }\\n      }\\n\\n      li.big-menu + li.bg-menu-small,\\n      li.bg-menu-small + li.bg-menu-gold {\\n        margin-top: 30px;\\n      }\\n\\n      li.bg-menu-gold + li.bg-menu-gold {\\n        margin-top: 0;\\n      }\\n\\n      li.has-arrow a::before {\\n        content: \\\"\\\";\\n        background: url(\\\"./../../assets/images/arrow-right-gold.svg\\\");\\n        background-size: cover;\\n        color: $secondaryColor;\\n        display: inline-block;\\n        width: 15px;\\n        height: 15px;\\n        margin-bottom: 3px;\\n        transform: rotate(45deg);\\n      }\\n    }\\n\\n    .menu-bottom {\\n      width: 100%;\\n\\n      .burger-bottom {\\n        width: fit-content;\\n        text-align: right;\\n        display: flex;\\n        flex-direction: column;\\n        margin-right: 0;\\n        padding-left: 100px;\\n        margin-left: auto;\\n        align-items: flex-end;\\n        border-top: 1px solid $lightGrayTransparent;\\n\\n        .burger-legal-footer {\\n          padding: 0;\\n          margin-top: 40px;\\n          display: flex;\\n          flex-direction: row;\\n          justify-content: flex-end;\\n          gap: 10px;\\n\\n          li {\\n            a {\\n              color: $lightGray;\\n              font-size: 0.8rem;\\n              text-transform: uppercase;\\n              text-decoration: none;\\n            }\\n\\n            & + li {\\n              &::before {\\n                content: \\\"•\\\";\\n                margin-right: 10px;\\n                color: $lightGray;\\n              }\\n            }\\n          }\\n        }\\n\\n        .burger-legal-copy {\\n          display: flex;\\n          justify-content: flex-end;\\n          gap: 10px;\\n          align-items: center;\\n\\n          .burger-legal-links,\\n          .burger-legal-copyright {\\n            color: $lightGray;\\n            font-size: 0.8rem;\\n            letter-spacing: 1px;\\n            text-transform: uppercase;\\n            margin: 0;\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@charset \\\"UTF-8\\\";\\n/*!\\n * Hamburgers\\n * @description Tasty CSS-animated hamburgers\\n * @author Jonathan Suh @jonsuh\\n * @site https://jonsuh.com/hamburgers\\n * @link https://github.com/jonsuh/hamburgers\\n */\\n\\n// Settings\\n// ==================================================\\n$hamburger-padding-x           : 15px !default;\\n$hamburger-padding-y           : 15px !default;\\n$hamburger-layer-width         : 40px !default;\\n$hamburger-layer-height        : 4px !default;\\n$hamburger-layer-spacing       : 6px !default;\\n$hamburger-layer-color         : #000 !default;\\n$hamburger-layer-border-radius : 4px !default;\\n$hamburger-hover-opacity       : 0.7 !default;\\n$hamburger-active-layer-color  : $hamburger-layer-color !default;\\n$hamburger-active-hover-opacity: $hamburger-hover-opacity !default;\\n\\n// To use CSS filters as the hover effect instead of opacity,\\n// set $hamburger-hover-use-filter as true and\\n// change the value of $hamburger-hover-filter accordingly.\\n$hamburger-hover-use-filter   : false !default;\\n$hamburger-hover-filter       : opacity(50%) !default;\\n$hamburger-active-hover-filter: $hamburger-hover-filter !default;\\n\\n// Types (Remove or comment out what you don’t need)\\n// ==================================================\\n$hamburger-types: (\\n  3dx,\\n  3dx-r,\\n  3dy,\\n  3dy-r,\\n  3dxy,\\n  3dxy-r,\\n  arrow,\\n  arrow-r,\\n  arrowalt,\\n  arrowalt-r,\\n  arrowturn,\\n  arrowturn-r,\\n  boring,\\n  collapse,\\n  collapse-r,\\n  elastic,\\n  elastic-r,\\n  emphatic,\\n  emphatic-r,\\n  minus,\\n  slider,\\n  slider-r,\\n  spin,\\n  spin-r,\\n  spring,\\n  spring-r,\\n  stand,\\n  stand-r,\\n  squeeze,\\n  vortex,\\n  vortex-r\\n) !default;\\n\\n// Base Hamburger (We need this)\\n// ==================================================\\n@import \\\"base\\\";\\n\\n// Hamburger types\\n// ==================================================\\n@import \\\"types/3dx\\\";\\n@import \\\"types/3dx-r\\\";\\n@import \\\"types/3dy\\\";\\n@import \\\"types/3dy-r\\\";\\n@import \\\"types/3dxy\\\";\\n@import \\\"types/3dxy-r\\\";\\n@import \\\"types/arrow\\\";\\n@import \\\"types/arrow-r\\\";\\n@import \\\"types/arrowalt\\\";\\n@import \\\"types/arrowalt-r\\\";\\n@import \\\"types/arrowturn\\\";\\n@import \\\"types/arrowturn-r\\\";\\n@import \\\"types/boring\\\";\\n@import \\\"types/collapse\\\";\\n@import \\\"types/collapse-r\\\";\\n@import \\\"types/elastic\\\";\\n@import \\\"types/elastic-r\\\";\\n@import \\\"types/emphatic\\\";\\n@import \\\"types/emphatic-r\\\";\\n@import \\\"types/minus\\\";\\n@import \\\"types/slider\\\";\\n@import \\\"types/slider-r\\\";\\n@import \\\"types/spin\\\";\\n@import \\\"types/spin-r\\\";\\n@import \\\"types/spring\\\";\\n@import \\\"types/spring-r\\\";\\n@import \\\"types/stand\\\";\\n@import \\\"types/stand-r\\\";\\n@import \\\"types/squeeze\\\";\\n@import \\\"types/vortex\\\";\\n@import \\\"types/vortex-r\\\";\\n\\n// ==================================================\\n// Cooking up additional types:\\n//\\n// The Sass for each hamburger type should be nested\\n// inside an @if directive to check whether or not\\n// it exists in $hamburger-types so only the CSS for\\n// included types are generated.\\n//\\n// e.g. hamburgers/types/_new-type.scss\\n//\\n// @if index($hamburger-types, new-type) {\\n//   .hamburger--new-type {\\n//     ...\\n//   }\\n// }\\n\",\"@use \\\"sass:math\\\";\\n\\n// Hamburger\\n// ==================================================\\n.hamburger {\\n  padding: $hamburger-padding-y $hamburger-padding-x;\\n  display: inline-block;\\n  cursor: pointer;\\n\\n  transition-property: opacity, filter;\\n  transition-duration: 0.15s;\\n  transition-timing-function: linear;\\n\\n  // Normalize (<button>)\\n  font: inherit;\\n  color: inherit;\\n  text-transform: none;\\n  background-color: transparent;\\n  border: 0;\\n  margin: 0;\\n  overflow: visible;\\n\\n  &:hover {\\n    @if $hamburger-hover-use-filter == true {\\n      filter: $hamburger-hover-filter;\\n    }\\n    @else {\\n      opacity: $hamburger-hover-opacity;\\n    }\\n  }\\n\\n  &.is-active {\\n    &:hover {\\n      @if $hamburger-hover-use-filter == true {\\n        filter: $hamburger-active-hover-filter;\\n      }\\n      @else {\\n        opacity: $hamburger-active-hover-opacity;\\n      }\\n    }\\n\\n    .hamburger-inner,\\n    .hamburger-inner::before,\\n    .hamburger-inner::after {\\n      background-color: $hamburger-active-layer-color;\\n    }\\n  }\\n}\\n\\n.hamburger-box {\\n  width: $hamburger-layer-width;\\n  height: $hamburger-layer-height * 3 + $hamburger-layer-spacing * 2;\\n  display: inline-block;\\n  position: relative;\\n}\\n\\n.hamburger-inner {\\n  display: block;\\n  top: 50%;\\n  margin-top: math.div($hamburger-layer-height, -2);\\n\\n  &,\\n  &::before,\\n  &::after {\\n    width: $hamburger-layer-width;\\n    height: $hamburger-layer-height;\\n    background-color: $hamburger-layer-color;\\n    border-radius: $hamburger-layer-border-radius;\\n    position: absolute;\\n    transition-property: transform;\\n    transition-duration: 0.15s;\\n    transition-timing-function: ease;\\n  }\\n\\n  &::before,\\n  &::after {\\n    content: \\\"\\\";\\n    display: block;\\n  }\\n\\n  &::before {\\n    top: ($hamburger-layer-spacing + $hamburger-layer-height) * -1;\\n  }\\n\\n  &::after {\\n    bottom: ($hamburger-layer-spacing + $hamburger-layer-height) * -1;\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dx) {\\n  /*\\n   * 3DX\\n   */\\n  .hamburger--3dx {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateY(180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dx-r) {\\n  /*\\n   * 3DX Reverse\\n   */\\n  .hamburger--3dx-r {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateY(-180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dy) {\\n  /*\\n   * 3DY\\n   */\\n  .hamburger--3dy {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateX(-180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dy-r) {\\n  /*\\n   * 3DY Reverse\\n   */\\n  .hamburger--3dy-r {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0.645, 0.045, 0.355, 1),\\n                  background-color 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n\\n      &::before,\\n      &::after {\\n        transition: transform 0s 0.1s cubic-bezier(0.645, 0.045, 0.355, 1);\\n      }\\n    }\\n\\n    &.is-active {\\n      .hamburger-inner {\\n        background-color: transparent !important;\\n        transform: rotateX(180deg);\\n\\n        &::before {\\n          transform: translate3d(0, $hamburger-layer-height + $hamburger-layer-spacing, 0) rotate(45deg);\\n        }\\n\\n        &::after {\\n          transform: translate3d(0, ($hamburger-layer-height + $hamburger-layer-spacing) * -1, 0) rotate(-45deg);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",\"@if index($hamburger-types, 3dxy) {\\n  /*\\n   * 3DXY\\n   */\\n  .hamburger--3dxy {\\n    .hamburger-box {\\n      perspective: $hamburger-layer-width * 2;\\n    }\\n\\n    .hamburger-inner {\\n      transition: transform 0.15s cubic-bezier(0